# -*- coding: utf-8 -*-

"""
동국대학교 이메일 수집 통합 실행 파일

실행 결과:
    1) 동국대_전체_원본_yyyymmddhhmmss.xlsx
       - 중복 제거 안 함
       - 이메일 빈값 제거 안 함
       - 이메일 형식 아닌 값 제거 안 함

    2) 동국대_전체_정리본_yyyymmddhhmmss.xlsx
       - 이메일 빈값 제거
       - 이메일 형식 아닌 값 제거
       - 이메일 소문자 기준 중복 제거
       - 같은 이메일은 위에서 처음 나온 1개 row만 유지

필요 패키지:
    pip install selenium pandas beautifulsoup4 openpyxl requests
"""

import os
import re
import runpy
import base64
from datetime import datetime

import pandas as pd
from openpyxl import load_workbook
from openpyxl.styles import Alignment


EMAIL_RE = r"[A-Za-z0-9._%+-]+@[A-Za-z0-9.-]+\.[A-Za-z]{2,}"

PART_DIR = "동국대_통합_임시"

PARTS = [
    {
        "name": "대학",
        "filename": "dongguk_part_college.py",
        "output": "동국대_교수목록.xlsx",
        "source_b64": ""
    },
    {
        "name": "대학원",
        "filename": "dongguk_part_graduate.py",
        "output": "동국대_대학원_교수목록.xlsx",
        "source_b64": ""
    },
    {
        "name": "산학협력단",
        "filename": "dongguk_part_sanhak.py",
        "output": "동국대_산학협력단_행정.xlsx",
        "source_b64": ""
    }
]

FINAL_COLUMNS = [
    "구분",
    "대분류",
    "중분류",
    "소분류",
    "직위",
    "업무",
    "이름",
    "이메일",
    "URL",
    "학과URL",
    "교수URL"
]


def now_text():
    return datetime.now().strftime("%Y%m%d%H%M%S")


def clean_email(value):
    value = str(value).strip()

    if not value or value.lower() == "nan":
        return ""

    match = re.search(EMAIL_RE, value)
    if not match:
        return ""

    return match.group(0).strip().strip(".,;:)'")


def delete_old_part_outputs():
    for part in PARTS:
        output = part["output"]
        if os.path.exists(output):
            os.remove(output)


def write_part_files():
    if not os.path.exists(PART_DIR):
        os.makedirs(PART_DIR)

    for part in PARTS:
        source = base64.b64decode(part["source_b64"]).decode("utf-8")
        path = os.path.join(PART_DIR, part["filename"])

        with open(path, "w", encoding="utf-8") as f:
            f.write(source)

        part["path"] = path


def run_part(part):
    print("\n[실행]", part["name"], "수집 시작")

    try:
        runpy.run_path(part["path"], run_name="__main__")
        print("[완료]", part["name"], "수집 완료")
    except Exception as e:
        print("[실패]", part["name"], str(e))


def normalize_df(df, part_name):
    df = df.copy()

    if "구분" not in df.columns:
        df["구분"] = part_name

    for col in FINAL_COLUMNS:
        if col not in df.columns:
            df[col] = ""

    if part_name == "산학협력단":
        df["구분"] = "산학협력단"
        df["소분류"] = df["소분류"].replace("", "행정")
        df["업무"] = df["업무"].replace("", "행정")

    return df[FINAL_COLUMNS]


def read_part_excels():
    dfs = []

    for part in PARTS:
        output = part["output"]

        if not os.path.exists(output):
            print("[스킵] 결과 파일 없음", output)
            continue

        df = pd.read_excel(output)
        df = normalize_df(df, part["name"])
        dfs.append(df)

        print("[읽기]", output, len(df), "건")

    if not dfs:
        return pd.DataFrame(columns=FINAL_COLUMNS)

    return pd.concat(dfs, ignore_index=True)


def make_clean_df(df):
    clean_df = df.copy()
    clean_df["이메일"] = clean_df["이메일"].apply(clean_email)
    clean_df = clean_df[clean_df["이메일"] != ""].copy()
    clean_df["_email_key"] = clean_df["이메일"].str.lower()
    clean_df = clean_df.drop_duplicates(subset=["_email_key"], keep="first")
    clean_df = clean_df.drop(columns=["_email_key"])
    return clean_df


def format_excel(filename):
    wb = load_workbook(filename)
    ws = wb.active
    ws.freeze_panes = "A2"

    for row in ws.iter_rows():
        for cell in row:
            cell.alignment = Alignment(vertical="top", wrap_text=True)

    for col in ws.columns:
        max_len = 0
        col_letter = col[0].column_letter

        for cell in col:
            text = str(cell.value) if cell.value is not None else ""
            if len(text) > max_len:
                max_len = len(text)

        width = max_len + 2
        if width < 12:
            width = 12
        if width > 50:
            width = 50

        ws.column_dimensions[col_letter].width = width

    wb.save(filename)


def save_final_excels(df):
    ts = now_text()
    original_file = "동국대_전체_원본_" + ts + ".xlsx"
    clean_file = "동국대_전체_정리본_" + ts + ".xlsx"

    clean_df = make_clean_df(df)

    df.to_excel(original_file, index=False)
    clean_df.to_excel(clean_file, index=False)

    format_excel(original_file)
    format_excel(clean_file)

    print("\n[엑셀] 원본 저장", original_file, len(df), "건")
    print("[엑셀] 정리본 저장", clean_file, len(clean_df), "건")


def main():
    print("[시작] 동국대학교 이메일 통합 수집")

    delete_old_part_outputs()
    write_part_files()

    for part in PARTS:
        run_part(part)

    df = read_part_excels()
    save_final_excels(df)

    print("[종료] 전체 작업 완료")


if __name__ == "__main__":
    main()
